.btn {
  background: #6366f1;
  color: white;
  padding: 10px 24px;
  border: none;
  border-radius: 8px;
  cursor: pointer;
  transition: all 0.3s ease;
}
.btn:hover {
  background: #4338ca;
  box-shadow: 0 6px 16px rgba(0,0,0,0.3);
}

.card {
  width: 160px;
  background: white;
  border: 1px solid #e2e8f0;
  border-radius: 10px;
  padding: 14px;
  transition: transform 0.3s ease, box-shadow 0.3s ease;
}
.card:hover {
  transform: translateY(-8px) scale(1.03);
  box-shadow: 0 12px 24px rgba(0,0,0,0.18);
}

.frame { width: 140px; height: 90px; overflow: hidden; border-radius: 10px; display:inline-block; }
.frame img { width: 100%; height: 100%; object-fit: cover; transition: transform 0.4s ease; }
.frame:hover img { transform: scale(1.15); }

.spin { display: inline-block; font-size: 1.6rem; transition: transform 0.4s ease; }
.spin:hover { transform: rotate(180deg); }

.press { padding: 8px 20px; cursor: pointer; transition: transform 0.1s; }
.press:active { transform: scale(0.94); }
